// Database Connector Tool
const { Pool } = require('pg');

class DatabaseConnector {
  constructor() {
    this.pool = new Pool({
      connectionString: process.env.POSTGRES_CONNECTION
    });
  }

  async execute(operation, data) {
    const client = await this.pool.connect();
    try {
      switch(operation) {
        case 'getCustomer':
          return await this.getCustomer(client, data.phoneNumber);
        case 'upsertCustomer':
          return await this.upsertCustomer(client, data);
        case 'createSale':
          return await this.createSale(client, data);
        case 'scheduleFollowUp':
          return await this.scheduleFollowUp(client, data);
        default:
          throw new Error('Operación no válida');
      }
    } finally {
      client.release();
    }
  }

  async getCustomer(client, phoneNumber) {
    const result = await client.query(
      'SELECT * FROM customers WHERE phone_number = $1',
      [phoneNumber]
    );
    return result.rows[0] || null;
  }

  async upsertCustomer(client, customerData) {
    const query = `
      INSERT INTO customers (phone_number, company_name, contact_name, email, industry)
      VALUES ($1, $2, $3, $4, $5)
      ON CONFLICT (phone_number) DO UPDATE SET
        company_name = EXCLUDED.company_name,
        contact_name = EXCLUDED.contact_name,
        email = EXCLUDED.email,
        industry = EXCLUDED.industry,
        updated_at = CURRENT_TIMESTAMP
      RETURNING *
    `;
    const result = await client.query(query, [
      customerData.phoneNumber,
      customerData.companyName,
      customerData.contactName,
      customerData.email,
      customerData.industry
    ]);
    return result.rows[0];
  }
}

module.exports = DatabaseConnector;

